from jinja2 import Environment

env = Environment(extensions=['jinja2.ext.i18n'])

class Translations:
    def gettext(self, s):
        return 'GETTEXT:' + s
    def ngettext(self, s, p, n):
        return 'NGETTEXT:' + (s if n == 1 else p)
    def dgettext(self, d, s):
        return f'DGETTEXT[{d}]:' + s
    def dngettext(self, d, s, p, n):
        return f'DNGETTEXT[{d}]:' + (s if n == 1 else p)

env.install_gettext_translations(Translations())

t = env.from_string('{% trans domain=\"admin\" %}Hello{% endtrans %}')
print(t.render())

t2 = env.from_string('{% trans %}Hello{% endtrans %}')
print(t2.render())

t3 = env.from_string('{% trans domain=\"admin\", count=5 %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(t3.render())

t4 = env.from_string('{% trans count=5, domain=\"admin\" %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(t4.render())

try:
    env.from_string('{% trans domain=\"a\" domain=\"b\" %}x{% endtrans %}')
except Exception as e:
    print('duplicate error:', e)

try:
    env.from_string('{% trans domain=somevar %}x{% endtrans %}')
except Exception as e:
    print('non-literal error:', e)
